// Mode: Run once for each item
// 1) item meta: chỉ chứa Store? và Email
// 2) item file: giữ nguyên toàn bộ binary (Files__*) của input

const meta = {
  Store: ($json['Store?'] ?? '').toUpperCase(),
  Email: $json['Email:'] ?? ''
};

const bins = $input.item.binary || $binary || {};
const hasBin = Object.keys(bins).length > 0;

const out = [];
out.push({ json: meta });               // item 1: metadata

if (hasBin) {
  out.push({ json: {}, binary: { ...bins } });  // item 2: binary
}

return out;

// Mode: Run once for each item
// Tách mọi binary Files__* -> mỗi file thành 1 item, rename key => data
const bins = $input.item.binary || $binary || {};
const out = [];
let i = 0;

for (const [k, bin] of Object.entries(bins)) {
  // Bỏ điều kiện Files__* pattern, chỉ kiểm tra extension .xlsx
  const fileName = bin.fileName || `file_${i}.xlsx`;

  // Chỉ lấy file có extension .xlsx
  if (!fileName.toLowerCase().endsWith('.xlsx')) continue;

  out.push({
    json: { index: i, fileName },
    binary: { data: { ...bin, fileName } }        // đổi key -> data
  });
  i++;
}

return out;

